INSERT INTO `lesson_topics` (`id`, `lesson_id`, `title`, `type`, `video_provider`, `video_id`, `video_file_path`, `text_content`, `file_path`, `worksheet_files`, `quiz_id`, `interactive_config`, `image_attachments`, `slideshow_data`, `duration`, `is_prerequisite`, `order`, `created_at`, `updated_at`) VALUES
(2, 1, 'Children grow taller and stronger', 'text', NULL, NULL, NULL, '<p>Children grow taller and stronger&nbsp;<span style=\"background-color: #000000;\"><mark class=\"HxTRcb\">through a combination of nutrient-dense nutrition, adequate sleep, and regular physical activity</mark>,</span> which support bone development, muscle growth, and hormone production. Key nutrients include protein for tissue repair, calcium and vitamin D for bone strength, and zinc for overall growth.</p>\r\n<p>&nbsp;</p>\r\n<div class=\"Y3BBE\" data-sfc-cp=\"\" data-hveid=\"CAIQAA\" data-processed=\"true\"><strong class=\"Yjhzub\">Key Factors for Growth:</strong><button class=\"rBl3me\" tabindex=\"0\" data-amic=\"true\" data-icl-uuid=\"84495b08-9ac6-4047-a925-87205169e8e0\" aria-label=\"View related links\" data-wiz-attrbind=\"disabled=vSq50e_p/C5gNJc;aria-label=vSq50e_p/bOjMyf;class=vSq50e_p/UpSNec\" data-ved=\"2ahUKEwiN4Nqh2dqSAxW3a_UHHelDD3sQye0OegQIAhAB\" data-processed=\"true\"></button></div>\r\n<ul class=\"KsbFXc U6u95\" data-processed=\"true\">\r\n<li data-hveid=\"CAMQAA\" data-processed=\"true\"><span class=\"T286Pc\" data-sfc-cp=\"\" data-processed=\"true\"><strong class=\"Yjhzub\" data-processed=\"true\">Nutrition:</strong>&nbsp;A balanced diet includes lean meats (chicken, beef), poultry, fish, eggs, dairy products (milk, yogurt), and vegetables like broccoli and spinach.</span></li>\r\n<li data-hveid=\"CAMQAQ\" data-processed=\"true\"><span class=\"T286Pc\" data-sfc-cp=\"\" data-processed=\"true\"><strong class=\"Yjhzub\" data-processed=\"true\">Nutrients:</strong></span>\r\n<ul class=\"KsbFXc U6u95\" data-processed=\"true\">\r\n<li data-hveid=\"CAMQAg\" data-processed=\"true\"><span class=\"T286Pc\" data-sfc-cp=\"\" data-processed=\"true\"><strong class=\"Yjhzub\" data-processed=\"true\">Protein:</strong>&nbsp;Essential for muscle, bone, and tissue development.</span></li>\r\n<li data-hveid=\"CAMQAw\" data-processed=\"true\"><span class=\"T286Pc\" data-sfc-cp=\"\" data-processed=\"true\"><strong class=\"Yjhzub\" data-processed=\"true\">Calcium &amp; Vitamin D:</strong>&nbsp;Crucial for building strong bones.</span></li>\r\n<li data-hveid=\"CAMQBA\" data-processed=\"true\"><span class=\"T286Pc\" data-sfc-cp=\"\" data-processed=\"true\"><strong class=\"Yjhzub\" data-processed=\"true\">Zinc:</strong>&nbsp;Supports growth hormone function, found in nuts, seeds, and whole grains.</span></li>\r\n</ul>\r\n</li>\r\n<li data-hveid=\"CAMQBQ\" data-processed=\"true\"><span class=\"T286Pc\" data-sfc-cp=\"\" data-processed=\"true\"><strong class=\"Yjhzub\" data-processed=\"true\">Sleep:</strong> Essential, as growth hormone works while children are asleep</span></li>\r\n<li data-hveid=\"CAMQBQ\" data-processed=\"true\"><span class=\"T286Pc\" data-sfc-cp=\"\" data-processed=\"true\"><strong class=\"Yjhzub\" data-processed=\"true\">Exercise:</strong>&nbsp;Regular activity strengthens muscles and bones.</span><span class=\"vKEkVd\" data-animation-atomic=\"\" data-wiz-attrbind=\"class=vSq50e_1f/TKHnVd\" data-processed=\"true\"><span aria-hidden=\"true\" data-processed=\"true\">&nbsp;</span><button class=\"rBl3me IWyTpf pjvauc\" tabindex=\"0\" data-amic=\"true\" data-icl-uuid=\"5d17adf9-e952-43a6-a01c-0a4e01e43ed1\" aria-label=\"Vinmec (+6) - View related links\" data-wiz-attrbind=\"disabled=vSq50e_1f/C5gNJc;aria-label=vSq50e_1f/bOjMyf;class=vSq50e_1f/UpSNec\" data-ved=\"2ahUKEwiN4Nqh2dqSAxW3a_UHHelDD3sQye0OegQIAxAH\" data-processed=\"true\"></button></span></li>\r\n</ul>\r\n<ul class=\"KsbFXc U6u95\" data-processed=\"true\">\r\n<li data-hveid=\"CAUQAg\" data-processed=\"true\">&nbsp;</li>\r\n</ul>', NULL, NULL, NULL, NULL, '[{\"path\":\"lesson-images\\/fzflzyy0A5AmShPnGeUteElO5juKtCwMvvIscPYB.png\",\"caption\":null,\"original_name\":\"image_2026-02-15_125306216.png\"}]', NULL, 2, 1, 1, '2026-02-14 20:54:52', '2026-02-14 20:54:52'),
(3, 1, 'Feelings can change', 'video', 'local', NULL, 'videos/tSn38U1sUUInAyCBr0mzQxtexKkmtmsIqwoqICdm.mp4', 'Feelings are temporary and can change from moment to moment. Understanding that emotions are not permanent helps children build resilience and manage their reactions more effectively.', NULL, NULL, NULL, NULL, NULL, NULL, 2, 1, 2, '2026-02-15 00:03:45', '2026-02-15 00:03:45'),
(4, 1, 'Worksheet Assessment', 'worksheet', NULL, NULL, NULL, 'This is a test instruction', 'worksheets/MRCWmUVgr0497jtVQFHex2ZjSopmX7DDiuGt7XQH.pdf', NULL, NULL, NULL, NULL, NULL, 1, 1, 3, '2026-02-16 04:20:00', '2026-02-16 04:20:00'),
(5, 1, 'Test Worksheet Multiple', 'worksheet', NULL, NULL, NULL, 'This is a test instruction', 'worksheets/1M1VbveuZaMgj48wbgpk9B8nXiSNeeo8wSHXuaAw.pdf', '[{\"path\":\"worksheets\\/1M1VbveuZaMgj48wbgpk9B8nXiSNeeo8wSHXuaAw.pdf\",\"original_name\":\"Laravel12 Artisan Cheatsheet 2025 (1).pdf\",\"mime_type\":\"application\\/pdf\",\"size\":82636},{\"path\":\"worksheets\\/CKr6w538P6S1Ve63V0WmPdN3xAFTgtToPVz806RX.pdf\",\"original_name\":\"VS-Code-Cheat-Sheet-2025.pdf\",\"mime_type\":\"application\\/pdf\",\"size\":139344}]', NULL, NULL, NULL, NULL, 1, 1, 4, '2026-02-16 05:15:57', '2026-02-16 05:15:57'),
(11, 1, 'Everyone is different', 'text', NULL, NULL, NULL, '<div class=\"Y3BBE\" data-sfc-cp=\"\" data-hveid=\"CAEQAA\" data-processed=\"true\">\"Everyone is different\" is a central theme in many educational, children&rsquo;s, and personal development resources, designed to celebrate uniqueness, foster inclusivity, and teach empathy. Content on this topic generally focuses on the idea that despite variations in appearance, ability, culture, or personality, everyone is special and worthy of respect.<span aria-hidden=\"true\" data-processed=\"true\">&nbsp;</span>\r\n<div class=\"Fwa2Od\" data-animation-skip=\"\" data-signal-inputs=\"scS1X=Ksdude_a/scS1X\" data-ved=\"2ahUKEwjA0vGs39-SAxU7qVYBHfvDGpsQ3s0SegQIARAC\" data-processed=\"true\">&nbsp;</div>\r\n</div>\r\n<div class=\"Y3BBE\" data-sfc-cp=\"\" data-hveid=\"CAIQAA\" data-processed=\"true\"><strong class=\"Yjhzub\" data-processed=\"true\">Key Themes in \"Everyone is Different\" Content</strong></div>\r\n<ul class=\"KsbFXc U6u95\" style=\"list-style-type: disc;\" data-processed=\"true\">\r\n<li data-hveid=\"CAMQAA\" data-processed=\"true\"><span class=\"T286Pc\" data-sfc-cp=\"\" data-processed=\"true\"><strong class=\"Yjhzub\" data-processed=\"true\">Celebrating Uniqueness:</strong>&nbsp;Resources highlight that no two people are the same, covering differences in hair/eye color, skin tone, and physical abilities (wheelchairs, limb differences).</span></li>\r\n<li data-hveid=\"CAMQAQ\" data-processed=\"true\"><span class=\"T286Pc\" data-sfc-cp=\"\" data-processed=\"true\"><strong class=\"Yjhzub\" data-processed=\"true\">Diversity &amp; Inclusion:</strong>&nbsp;Content often explores different family structures (two dads, grandparents, single moms), languages, and cultural backgrounds to promote acceptance.</span></li>\r\n<li data-hveid=\"CAMQAg\" data-processed=\"true\"><span class=\"T286Pc\" data-sfc-cp=\"\" data-processed=\"true\"><strong class=\"Yjhzub\" data-processed=\"true\">Overcoming Stereotypes:</strong> The focus is on embracing differences as a strength rather than a barrier, discouraging teasing or bullying based on appearance or behavior.</span></li>\r\n</ul>\r\n<div class=\"Y3BBE\" data-sfc-cp=\"\" data-hveid=\"CAQQAA\" data-processed=\"true\"><strong class=\"Yjhzub\" data-processed=\"true\">Common Content Examples</strong></div>\r\n<ul class=\"KsbFXc U6u95\" data-processed=\"true\">\r\n<li data-hveid=\"CAUQAA\" data-processed=\"true\"><span class=\"T286Pc\" data-sfc-cp=\"\" data-processed=\"true\"><strong class=\"Yjhzub\" data-processed=\"true\">Children\'s Books:</strong>&nbsp;Titles like&nbsp;<em class=\"eujQNb\" data-processed=\"true\">Everyone is Different! A little book with a BIG message</em>&nbsp;(highlighting unique traits),&nbsp;<em class=\"eujQNb\" data-processed=\"true\">Everyone is Different, Everyone is Special</em>&nbsp;(addressing disabilities and physical differences), and&nbsp;<em class=\"eujQNb\" data-processed=\"true\">Everyone is Different and that\'s OK!</em>.</span></li>\r\n<li data-hveid=\"CAUQAQ\" data-processed=\"true\"><span class=\"T286Pc\" data-sfc-cp=\"\" data-processed=\"true\"><strong class=\"Yjhzub\" data-processed=\"true\">Educational Videos:</strong>&nbsp;Videos that discuss diversity in hair, skin, and preferences to show that differences make the world more interesting.</span></li>\r\n<li data-hveid=\"CAUQAg\" data-processed=\"true\"><span class=\"T286Pc\" data-sfc-cp=\"\" data-processed=\"true\"><strong class=\"Yjhzub\" data-processed=\"true\">Educational Materials:</strong><span class=\"T286Pc\" data-sfc-cp=\"\" data-processed=\"true\">&nbsp;Resources from organizations like the<strong>&nbsp;<span style=\"background-color: #000000;\" data-sfc-cp=\"\" data-processed=\"true\"><a class=\"H23r4e\" style=\"background-color: #000000;\" href=\"https://www.google.com/url?sa=i&amp;source=web&amp;rct=j&amp;url=https://www.thewatsoninstitute.org/resource/everyone-is-different/&amp;ved=2ahUKEwjA0vGs39-SAxU7qVYBHfvDGpsQy_kOegQIBRAD&amp;opi=89978449&amp;cd&amp;psig=AOvVaw2CTQ_1azKyiLTivOTUwZxL&amp;ust=1771390868113000\" target=\"_blank\" rel=\"noopener\" data-hveid=\"CAUQAw\" data-processed=\"true\">Watson Institute</a></span>,</strong> which offer, for example, a \"Facilitators Guide,\" PowerPoints, and activity cards to teach about differences in social skills</span>.</span><span aria-hidden=\"true\" data-processed=\"true\">&nbsp;</span></li>\r\n</ul>', NULL, NULL, NULL, NULL, '[{\"path\":\"lesson-images\\/WoilCLFa3492mDQb47wl8AIIFgF8hfmVLVTGqgoS.jpg\",\"caption\":\"E\",\"original_name\":\"thumbNailSample2.jpg\"},{\"path\":\"lesson-images\\/UWMA1eRybaKAeE7Lbnajeka5wnEIkz9ujxsUoq65.jpg\",\"caption\":\"A\",\"original_name\":\"thumbNailSample3.jpg\"},{\"path\":\"lesson-images\\/dCg2oIJ261b4iXAJqobemluPU13IYaxSHDQsbVAc.jpg\",\"caption\":\"D\",\"original_name\":\"thumbNailSample4.jpg\"},{\"path\":\"lesson-images\\/4XCiyBLYu9J9Nwe6DiWn7R9vIeF9kKb5Nyb7vmkZ.jpg\",\"caption\":\"C\",\"original_name\":\"ED3.jpg\"},{\"path\":\"lesson-images\\/AwkxZHDaespcy1y40AjnJQQGqQvTyOKDx5hjNanu.png\",\"caption\":\"B\",\"original_name\":\"ED2.png\"}]', '{\"enabled\":true,\"gallery_mode\":\"grid\",\"slideshow_mode\":\"slide\",\"auto_play\":false,\"show_thumbnails\":true,\"allow_toggle\":true}', 4, 1, 5, '2026-02-16 21:03:47', '2026-02-16 21:03:47');

